mapper.delete:
DELETE FROM file_asset
 WHERE id = #{id}
   AND owner_user_id = #{ownerUserId}
   AND kind = 'ATTACHMENT'
   AND ref_type = 'COLLAB_MESSAGE'
   AND ref_id IS NULL
   AND created_at < #{cutoff}

DELETE FROM file_asset
 WHERE id = #{id}
   AND owner_user_id = #{ownerUserId}
   AND kind = 'ATTACHMENT'
   AND ref_type = 'AUTO_PREP_PENDING'
   AND ref_id IS NULL
   AND created_at < #{cutoff}

DELETE FROM file_asset
 WHERE id = #{id}
   AND owner_user_id = #{ownerUserId}
   AND kind IN ('AUDIO', 'VIDEO')
   AND ref_type = 'INTERVIEW_ANSWER'
   AND ref_id IS NULL
   AND created_at < #{cutoff}

DELETE f
  FROM file_asset f
 WHERE f.id = #{id}
   AND f.owner_user_id = #{ownerUserId}
   AND f.kind IN ('AUDIO', 'VIDEO')
   AND f.ref_type = 'INTERVIEW_ANSWER'
   AND f.ref_id IS NOT NULL
   AND f.created_at < #{cutoff}
   AND NOT EXISTS (
       SELECT 1
         FROM interview_answer a
        WHERE a.id = f.ref_id
   )

DELETE FROM file_asset
 WHERE id = #{id}
   AND owner_user_id = #{ownerUserId}
   AND kind = #{expectedKind}
   AND ref_type = #{refType}
   AND ref_id = #{refId}

DELETE FROM file_asset
 WHERE id = #{id}
   AND owner_user_id = #{ownerUserId}
   AND kind IN ('RESUME', 'PORTFOLIO')
